import { useState, useEffect, useCallback } from 'react';
import { useAuth } from '../utils/AuthContext';
import { useSync } from '../hooks/useSync';
import { api } from '../utils/api';
import { savePendingTransaction, getAllLocal } from '../utils/offlineStore';
import toast from 'react-hot-toast';

export default function AgentDashboard() {
  const { user, logout } = useAuth();
  const { isOnline, pendingCount, syncing, sync, refreshPending } = useSync();
  const [tab, setTab] = useState('entry');
  const [form, setForm] = useState({ customer_code: '', account_id: '', amount: '', payment_mode: 'CASH' });
  const [customer, setCustomer] = useState(null);
  const [fetchingCustomer, setFetchingCustomer] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [todayEntries, setTodayEntries] = useState([]);
  const [localEntries, setLocalEntries] = useState([]);

  const loadTodayEntries = useCallback(async () => {
    if (isOnline) {
      try {
        const data = await api.myToday();
        setTodayEntries(data);
      } catch {}
    }
    const all = await getAllLocal();
    setLocalEntries(all);
  }, [isOnline]);

  useEffect(() => { loadTodayEntries(); }, [loadTodayEntries]);

  const fetchCustomer = async () => {
    if (!form.customer_code.trim()) return;
    if (!isOnline) { toast.error('Need internet to fetch customer'); return; }
    setFetchingCustomer(true);
    try {
      const data = await api.getCustomer(form.customer_code.trim());
      setCustomer(data);
      setForm(f => ({
        ...f,
        account_id: data.accounts?.[0]?.id ? data.accounts[0].id.toString() : ''
      }));
    } catch (err) {
      toast.error('Customer not found');
      setCustomer(null);
    } finally {
      setFetchingCustomer(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!customer) { toast.error('Fetch customer first'); return; }
    if (!form.account_id) { toast.error('Select account'); return; }
    const amount = parseFloat(form.amount);
    if (!amount || amount <= 0) { toast.error('Invalid amount'); return; }

    setSubmitting(true);
    const selectedAccount = customer.accounts.find(a => a.id === parseInt(form.account_id));
    const entry = {
      offline_id: globalThis.crypto.randomUUID(),
      customer_id: customer.id,
      customer_name: customer.name,
      account_id: parseInt(form.account_id),
      amount,
      payment_mode: form.payment_mode,
      collected_at: new Date().toISOString(),
      agent_id: user.id,
      agent_name: user.name,
      remaining_balance: selectedAccount?.remaining_balance
    };

    await savePendingTransaction(entry);
    await refreshPending();

    if (isOnline) {
      try {
        await sync();
      } catch {}
    } else {
      toast('Saved offline. Will sync when online.', { icon: '📴' });
    }

    setForm({ customer_code: '', account_id: '', amount: '', payment_mode: 'CASH' });
    setCustomer(null);
    await loadTodayEntries();
    setSubmitting(false);
    toast.success('Entry saved!');
  };

  const today = new Date().toLocaleDateString('en-IN', { day: '2-digit', month: 'short', year: 'numeric' });

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)' }}>
      {/* Status bar */}
      <div className="status-bar">
        <div className={`dot ${isOnline ? 'online' : 'offline'}`} />
        <span style={{ color: isOnline ? 'var(--success)' : 'var(--danger)' }}>
          {isOnline ? 'ONLINE' : 'OFFLINE'}
        </span>
        {pendingCount > 0 && (
          <>
            <span style={{ color: 'var(--warning)', marginLeft: 8 }}>
              {pendingCount} pending
            </span>
            {isOnline && (
              <button
                onClick={sync}
                disabled={syncing}
                style={{ padding: '3px 10px', fontSize: 11, marginLeft: 4, borderRadius: 6 }}
                className="btn-primary"
              >
                {syncing ? 'Syncing...' : 'Sync Now'}
              </button>
            )}
          </>
        )}
        <span style={{ marginLeft: 'auto', color: 'var(--muted)', fontSize: 11 }}>{user.name}</span>
        <button onClick={logout} style={{ padding: '4px 10px', fontSize: 11, marginLeft: 8, borderRadius: 6, background: 'var(--surface2)', color: 'var(--muted)' }}>
          Logout
        </button>
      </div>

      <div className="page">
        <div className="tabs">
          <div className={`tab ${tab === 'entry' ? 'active' : ''}`} onClick={() => setTab('entry')}>
            + New Entry
          </div>
          <div className={`tab ${tab === 'today' ? 'active' : ''}`} onClick={() => { setTab('today'); loadTodayEntries(); }}>
            Today ({todayEntries.length + localEntries.filter(e => !e.synced).length})
          </div>
        </div>

        {tab === 'entry' && (
          <div className="card">
            <div style={{ marginBottom: 16, color: 'var(--muted)', fontSize: 13 }}>📅 {today}</div>
            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label>Customer ID / Code</label>
                <div style={{ display: 'flex', gap: 8 }}>
                  <input
                    value={form.customer_code}
                    onChange={e => { setForm({ ...form, customer_code: e.target.value }); setCustomer(null); }}
                    placeholder="e.g. C001 or 2"
                    onKeyDown={e => e.key === 'Enter' && (e.preventDefault(), fetchCustomer())}
                  />
                  <button
                    type="button"
                    onClick={fetchCustomer}
                    disabled={fetchingCustomer || !form.customer_code}
                    className="btn-secondary"
                    style={{ whiteSpace: 'nowrap', padding: '12px 16px' }}
                  >
                    {fetchingCustomer ? '...' : 'Fetch'}
                  </button>
                </div>
              </div>

              {customer && (
                <div style={{
                  background: 'var(--surface2)', borderRadius: 8, padding: 12,
                  marginBottom: 16, borderLeft: '3px solid var(--accent)'
                }}>
                  <div style={{ fontWeight: 'bold', fontSize: 16 }}>{customer.name}</div>
                  <div style={{ color: 'var(--muted)', fontSize: 12 }}>{customer.address}</div>
                  {customer.accounts?.[0] && (
                    <div style={{ marginTop: 8, fontSize: 12, color: 'var(--accent)' }}>
                      Current active account: #{customer.accounts[0].id}
                    </div>
                  )}
                  {customer.accounts?.map(acc => (
                    <div key={acc.id} style={{ marginTop: 8, fontSize: 12 }}>
                      <span className="badge badge-blue">Account #{acc.id}</span>
                      <span style={{ marginLeft: 8 }}>Balance: ₹{parseFloat(acc.remaining_balance || 0).toFixed(2)}</span>
                    </div>
                  ))}
                </div>
              )}

              {customer?.accounts?.length > 0 && (
                <div className="form-group">
                  <label>{customer.accounts.length > 1 ? 'Select Account' : 'Active Account'}</label>
                  <select value={form.account_id} onChange={e => setForm({ ...form, account_id: e.target.value })} required>
                    {customer.accounts.map(a => (
                      <option key={a.id} value={a.id}>
                        Account #{a.id} — Balance ₹{parseFloat(a.remaining_balance || 0).toFixed(2)}
                      </option>
                    ))}
                  </select>
                </div>
              )}

              <div className="form-group">
                <label>Amount (₹)</label>
                <input
                  type="number"
                  step="0.01"
                  min="1"
                  value={form.amount}
                  onChange={e => setForm({ ...form, amount: e.target.value })}
                  placeholder="0.00"
                  required
                  style={{ fontSize: 24, fontWeight: 'bold' }}
                />
              </div>

              <div className="form-group">
                <label>Payment Mode</label>
                <div style={{ display: 'flex', gap: 8 }}>
                  {['CASH', 'GPAY'].map(mode => (
                    <button
                      key={mode}
                      type="button"
                      onClick={() => setForm({ ...form, payment_mode: mode })}
                      style={{
                        flex: 1, padding: 14,
                        background: form.payment_mode === mode ? (mode === 'CASH' ? 'var(--success)' : '#1e40af') : 'var(--surface2)',
                        color: 'white',
                        borderRadius: 8,
                        border: '2px solid transparent',
                        fontSize: 16,
                        fontWeight: 'bold'
                      }}
                    >
                      {mode === 'CASH' ? '💵 Cash' : '📱 GPay'}
                    </button>
                  ))}
                </div>
              </div>

              <button
                type="submit"
                className="btn-primary"
                style={{ width: '100%', padding: 16, fontSize: 16, marginTop: 8 }}
                disabled={submitting || !customer}
              >
                {submitting ? 'Saving...' : `COLLECT ₹${form.amount || '0'}`}
              </button>
            </form>
          </div>
        )}

        {tab === 'today' && (
          <div>
            <div className="stats-grid">
              <div className="stat-card">
                <div className="value">{todayEntries.length}</div>
                <div className="label">Synced</div>
              </div>
              <div className="stat-card">
                <div className="value">{localEntries.filter(e => !e.synced).length}</div>
                <div className="label">Pending</div>
              </div>
              <div className="stat-card">
                <div className="value">
                  ₹{todayEntries.reduce((s, t) => s + parseFloat(t.amount), 0).toFixed(0)}
                </div>
                <div className="label">Total</div>
              </div>
            </div>

            {localEntries.filter(e => !e.synced).length > 0 && (
              <div style={{ marginBottom: 16 }}>
                <div style={{ color: 'var(--warning)', fontSize: 13, marginBottom: 8 }}>⚠ Offline (not synced)</div>
                {localEntries.filter(e => !e.synced).map(t => (
                  <div key={t.offline_id} className="card" style={{ marginBottom: 8, borderLeft: '3px solid var(--warning)' }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                      <span>{t.customer_name}</span>
                      <span style={{ color: 'var(--warning)' }}>₹{t.amount}</span>
                    </div>
                    <div style={{ fontSize: 12, color: 'var(--muted)' }}>
                      {t.payment_mode} — {new Date(t.collected_at).toLocaleTimeString('en-IN')}
                    </div>
                  </div>
                ))}
              </div>
            )}

            {todayEntries.map(t => (
              <div key={t.id} className="card" style={{ marginBottom: 8 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <div>
                    <span style={{ fontWeight: 'bold' }}>{t.customer_name}</span>
                    {t.duplicate_flag && <span className="badge badge-yellow" style={{ marginLeft: 8 }}>DUPLICATE</span>}
                  </div>
                  <span style={{ color: 'var(--success)', fontWeight: 'bold' }}>₹{parseFloat(t.amount).toFixed(2)}</span>
                </div>
                <div style={{ fontSize: 12, color: 'var(--muted)', marginTop: 4 }}>
                  {t.payment_mode} · {new Date(t.collected_at).toLocaleTimeString('en-IN')}
                </div>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}
